const items = $input.all();
const results = [];

const graphqlData = items[0]?.json?.data?.customers;
const edges = graphqlData?.edges || [];

const cursor = graphqlData?.pageInfo?.hasNextPage && edges.length > 0 
  ? edges[edges.length - 1]?.cursor 
  : null;
const hasNextPage = graphqlData?.pageInfo?.hasNextPage || false;

for (const edge of edges) {
  const node = edge.node;
  const ordersData = node.orders?.edges || [];

  if (ordersData.length === 0) continue; 

  const totalSpentStr = node.amountSpent?.amount || "0";
  const totalSpent = parseFloat(totalSpentStr);

  const orderCount = Number(node.numberOfOrders) || 1;
  const customerAOV = totalSpent / orderCount;

  const dates = ordersData
    .map(o => new Date(o.node.createdAt))
    .sort((a, b) => b.getTime() - a.getTime());

  let gaps = [];
  for (let i = 1; i < dates.length; i++) {
    gaps.push((dates[i - 1].getTime() - dates[i].getTime()) / (1000 * 60 * 60 * 24));
  }
  gaps.sort((a, b) => a - b);

  const median = gaps.length > 0 ? gaps[Math.floor(gaps.length / 2)] : 45;
  const lastOrder = dates[0];

  const daysSinceLast = (Date.now() - lastOrder.getTime()) / (1000 * 60 * 60 * 24);
  const score = median > 0 ? daysSinceLast / median : 0;

  let risk = 'LOW';
  if (score >= 2.0) {
    risk = 'HIGH';
  } else if (score >= 1.5) {
    risk = 'MEDIUM';
  } else {
    continue;
  }

  results.push({
    "Email": node.email,
    "Display Name": node.displayName,
    "Number Of Orders": node.numberOfOrders,
    "Expected Order Value": Math.round(customerAOV * 100) / 100,
    "Avg Order Days": Math.round(median),
    "Days Since Last Order": Math.round(daysSinceLast),
    "Risk Status": risk,
    "Last Order Date": lastOrder.toISOString().split('T')[0],
    cursor: cursor,
    hasNextPage: hasNextPage
  });
}

if (results.length === 0) {
  return [{ json: { cursor: cursor, hasNextPage: hasNextPage, isSignal: true } }];
}

return results;

const items = $input.all();
let highRiskCount = 0;
let mediumRiskCount = 0;
let highRiskRevenue = 0;
let mediumRiskRevenue = 0;

for (const item of items) {
  const risk = item.json['Risk Status'];
  const expectedValue = parseFloat(item.json['Expected Order Value'] || 0);

  if (risk === 'HIGH') {
    highRiskCount++;
    highRiskRevenue += expectedValue;
  }
  if (risk === 'MEDIUM') {
    mediumRiskCount++;
    mediumRiskRevenue += expectedValue;
  }
}

return [{
  json: {
    totalAtRisk: highRiskCount + mediumRiskCount,
    highRiskCount,
    mediumRiskCount,
    highRiskRevenue: Math.round(highRiskRevenue * 100) / 100,
    mediumRiskRevenue: Math.round(mediumRiskRevenue * 100) / 100,
    totalRevenueAtRisk: Math.round((highRiskRevenue + mediumRiskRevenue) * 100) / 100
  }
}];

const memory = $getWorkflowStaticData('global');

memory.allCustomers = memory.allCustomers || [];

const currentBatch = $input.all();
memory.allCustomers.push(...currentBatch);

return currentBatch;

parameters.query:
query CustomersByLastOrderDate($cursor: String, $filter: String!) {
  customers(first: 100, after: $cursor, query: $filter) {
    edges {
      cursor
      node {
        id
        email
        displayName
        numberOfOrders
        amountSpent {
          amount
        }
        orders(first: 5, reverse: true,  query: "financial_status:paid AND fulfillment_status:fulfilled") {
          edges {
            node {
              createdAt
            }
          }
        }
      }
    }
    pageInfo {
      hasNextPage
    }
  }
}

